import{_ as t,o as s,c as a,ai as n}from"./chunks/framework.Bke2s2V8.js";const m=JSON.parse('{"title":"Les adjectifs","description":"","frontmatter":{},"headers":[],"relativePath":"module-5-aller-plus-loin/adjectifs.md","filePath":"module-5-aller-plus-loin/adjectifs.md","lastUpdated":1773299234000}'),r={name:"module-5-aller-plus-loin/adjectifs.md"};function i(l,e,d,o,c,p){return s(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="les-adjectifs" tabindex="-1">Les adjectifs <a class="header-anchor" href="#les-adjectifs" aria-label="Permalink to “Les adjectifs”">​</a></h1><p><strong>Prérequis :</strong> <a href="./prepositions.html">Les prépositions</a></p><p><strong>Objectif :</strong> décliner les adjectifs epithetes selon le cas, le genre et le type d&#39;article qui précède.</p><p>Les adjectifs places avant un nom (epithetes) se déclinent. La terminaison change selon trois facteurs : le cas, le genre du nom, et le type de determinant qui précède (article défini, indefini, ou aucun).</p><h2 id="adjectif-attribut-invariable" tabindex="-1">Adjectif attribut : invariable <a class="header-anchor" href="#adjectif-attribut-invariable" aria-label="Permalink to “Adjectif attribut : invariable”">​</a></h2><p>Quand l&#39;adjectif est attribut (après <em>sein, werden, bleiben</em>), il est invariable :</p><ul><li><em>Der Kaffee ist <strong>heiß</strong>.</em> - Le cafe est chaud.</li><li><em>Das Buch ist <strong>interessant</strong>.</em> - Le livre est interessant.</li><li><em>Die Blumen sind <strong>schon</strong>.</em> - Les fleurs sont belles.</li></ul><h2 id="adjectif-epithete-trois-tableaux-selon-le-determinant" tabindex="-1">Adjectif épithète : trois tableaux selon le determinant <a class="header-anchor" href="#adjectif-epithete-trois-tableaux-selon-le-determinant" aria-label="Permalink to “Adjectif épithète : trois tableaux selon le determinant”">​</a></h2><h3 id="_1-apres-l-article-defini-der-die-das" tabindex="-1">1. Après l&#39;article défini (der, die, das) <a class="header-anchor" href="#_1-apres-l-article-defini-der-die-das" aria-label="Permalink to “1. Après l&#39;article défini (der, die, das)”">​</a></h3><p>L&#39;article défini porte déjà toute l&#39;information de genre/cas → la terminaison de l&#39;adjectif est presque toujours <strong>-en</strong>.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Cas</th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Féminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">Nominatif</td><td class="p-3 text-center">der alt<strong>e</strong> Mann</td><td class="p-3 text-center">die alt<strong>e</strong> Frau</td><td class="p-3 text-center">das alt<strong>e</strong> Haus</td><td class="p-3 text-center">die alt<strong>en</strong> Hauser</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">Accusatif</td><td class="p-3 text-center">den alt<strong>en</strong> Mann</td><td class="p-3 text-center">die alt<strong>e</strong> Frau</td><td class="p-3 text-center">das alt<strong>e</strong> Haus</td><td class="p-3 text-center">die alt<strong>en</strong> Hauser</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">Datif</td><td class="p-3 text-center">dem alt<strong>en</strong> Mann</td><td class="p-3 text-center">der alt<strong>en</strong> Frau</td><td class="p-3 text-center">dem alt<strong>en</strong> Haus</td><td class="p-3 text-center">den alt<strong>en</strong> Häusern</td></tr></tbody></table></div><h3 id="_2-apres-l-article-indefini-ein-eine-kein-mein" tabindex="-1">2. Après l&#39;article indefini (ein, eine, kein, mein...) <a class="header-anchor" href="#_2-apres-l-article-indefini-ein-eine-kein-mein" aria-label="Permalink to “2. Après l&#39;article indefini (ein, eine, kein, mein...)”">​</a></h3><p>Quand l&#39;article indefini ne marque pas le genre (ex : <em>ein</em> = masculin OU neutre au nominatif), l&#39;adjectif prend la marque a sa place.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Cas</th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Féminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">Nominatif</td><td class="p-3 text-center">ein alt<strong>er</strong> Mann</td><td class="p-3 text-center">eine alt<strong>e</strong> Frau</td><td class="p-3 text-center">ein alt<strong>es</strong> Haus</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">Accusatif</td><td class="p-3 text-center">einen alt<strong>en</strong> Mann</td><td class="p-3 text-center">eine alt<strong>e</strong> Frau</td><td class="p-3 text-center">ein alt<strong>es</strong> Haus</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">Datif</td><td class="p-3 text-center">einem alt<strong>en</strong> Mann</td><td class="p-3 text-center">einer alt<strong>en</strong> Frau</td><td class="p-3 text-center">einem alt<strong>en</strong> Haus</td></tr></tbody></table></div><div class="tip custom-block"><p class="custom-block-title">La &quot;casserole&quot; : presque tout finit en -en</p><p>Sauf aux nominatif et accusatif singulier (masculin, féminin, neutre), toutes les terminaisons sont <em>-en</em>. L&#39;image d&#39;une casserole avec un manche - les cases &quot;speciales&quot; sont les poignees, tout le reste est <em>-en</em>.</p></div><div class="warning custom-block"><p class="custom-block-title">Ne pas chercher a tout mémoriser d&#39;un coup</p><p>La déclinaison des adjectifs s&#39;acquiert par l&#39;exposition répétée à la langue plus que par la mémorisation des tableaux. Retiens les cas les plus courants (nominatif et accusatif avec article défini) et laisse les autres venir progressivement.</p></div>',16)])])}const f=t(r,[["render",i]]);export{m as __pageData,f as default};
